@namespace sv_15f8c3b5f5974dadba9cf7b1dd6a1fa2.Components.Pages.Settings
@using sv_15f8c3b5f5974dadba9cf7b1dd6a1fa2.Models
@inject ISettingsService SettingsService

<div class="security-section">
    <h4 class="mb-4">Security Settings</h4>

    @if (_loading)
    {
        <div class="text-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        @* Change Password Panel *@
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 role="button" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <h6 class="mb-0">Change Password</h6>
                <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>

                    @if (_passwordError is not null)
                    {
                        <div class="alert alert-danger py-2">@_passwordError</div>
                    }
                    @if (_passwordSuccess is not null)
                    {
                        <div class="alert alert-success py-2">@_passwordSuccess</div>
                    }

                    <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @if (_changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Update Password
                    </button>
                </div>
            }
        </div>

        @* Two-Factor Authentication *@
        <div class="card mb-4">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center">
                    <div>
                        <h6 class="mb-1">Two-Factor Authentication</h6>
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" id="twoFactor"
                               checked="@_twoFactorEnabled"
                               @onchange="e => _twoFactorEnabled = (bool)e.Value!" />
                    </div>
                </div>
                @if (_lastPasswordChange.HasValue)
                {
                    <small class="text-muted d-block mt-2">
                        Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
                    </small>
                }
            </div>
        </div>

        @* Active Sessions *@
        <div class="card mb-4">
            <div class="card-header">
                <h6 class="mb-0">Active Sessions</h6>
            </div>
            <div class="card-body p-0">
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead class="table-light">
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th class="text-end">Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td class="text-end">
                                        @if (session == _sessions.FirstOrDefault())
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                        else
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => PromptRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>

        @if (_revokeTarget is not null)
        {
            <RevokeSessionDialog Device="@_revokeTarget.Device"
                                 Location="@_revokeTarget.Location"
                                 OnConfirm="ConfirmRevokeAsync"
                                 OnCancel="() => _revokeTarget = null" />
        }

        @if (_revokeMessage is not null)
        {
            <div class="alert alert-success alert-dismissible mt-3 fade show" role="alert">
                @_revokeMessage
                <button type="button" class="btn-close" @onclick="() => _revokeMessage = null"></button>
            </div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private bool _passwordPanelOpen;
    private bool _changingPassword;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();

    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private string? _passwordSuccess;

    private ActiveSession? _revokeTarget;
    private string? _revokeMessage;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetSecuritySettingsAsync();
            _twoFactorEnabled = settings.TwoFactorEnabled;
            _lastPasswordChange = settings.LastPasswordChange;
            _sessions = new List<ActiveSession>(settings.Sessions);
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = null;

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "New password is required.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _passwordSuccess = "Password updated successfully!";
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _passwordError = $"Failed to change password: {ex.Message}";
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session)
    {
        _revokeTarget = session;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_revokeTarget is null) return;

        try
        {
            await SettingsService.RevokeSessionAsync(_revokeTarget.Id);
            _sessions.Remove(_revokeTarget);
            _revokeMessage = $"Session on {_revokeTarget.Device} has been revoked.";
        }
        catch (Exception ex)
        {
            _revokeMessage = $"Failed to revoke session: {ex.Message}";
        }
        finally
        {
            _revokeTarget = null;
        }
    }
}

@namespace sv_15f8c3b5f5974dadba9cf7b1dd6a1fa2.Components.Pages.Settings
@using sv_15f8c3b5f5974dadba9cf7b1dd6a1fa2.Models
@inject ISettingsService SettingsService

<div class="appearance-section">
    <h4 class="mb-4">Appearance Settings</h4>

    @if (_loading)
    {
        <div class="text-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                @* Theme *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Theme</h6>
                        @foreach (var theme in _themes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme}")" value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                @* Font Size *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Font Size</h6>
                        @foreach (var size in _fontSizes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size}")" value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>
                </div>

                @* Language *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Language</h6>
                        <select class="form-select" @bind="_language">
                            @foreach (var lang in _languages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>
                </div>

                @* Compact Mode *@
                <div class="card mb-4">
                    <div class="card-body">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch" id="compactMode"
                                   checked="@_compactMode" @onchange="e => _compactMode = (bool)e.Value!" />
                            <label class="form-check-label" for="compactMode">Compact Mode</label>
                        </div>
                        <small class="text-muted">Reduce spacing and padding throughout the interface.</small>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @if (_saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Save
                </button>

                @if (_successMessage is not null)
                {
                    <div class="alert alert-success alert-dismissible mt-3 fade show" role="alert">
                        @_successMessage
                        <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
                    </div>
                }
                @if (_errorMessage is not null)
                {
                    <div class="alert alert-danger alert-dismissible mt-3 fade show" role="alert">
                        @_errorMessage
                        <button type="button" class="btn-close" @onclick="() => _errorMessage = null"></button>
                    </div>
                }
            </div>

            @* Live Preview *@
            <div class="col-md-5">
                <div class="card sticky-top" style="top: 1rem;">
                    <div class="card-header">
                        <h6 class="mb-0">Live Preview</h6>
                    </div>
                    <div class="card-body preview-area @PreviewThemeClass" style="@PreviewFontStyle">
                        <div class="@(_compactMode ? "compact-preview" : "normal-preview")">
                            <h6>Sample Heading</h6>
                            <p>This is how your content will look with the selected settings.</p>
                            <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
                                <span class="badge bg-primary">Badge</span>
                                <span class="badge bg-secondary">Label</span>
                            </div>
                            <button class="btn btn-sm btn-primary">Sample Button</button>
                        </div>
                        <div class="mt-2 small text-muted">
                            Theme: @_theme · Font: @_fontSize · Lang: @_language
                            @if (_compactMode) { <span>· Compact</span> }
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;
    private string? _errorMessage;

    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    private string PreviewThemeClass => _theme switch
    {
        "Dark" => "preview-dark",
        "Light" => "preview-light",
        _ => "preview-system"
    };

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetAppearanceAsync();
            _theme = settings.Theme;
            _fontSize = settings.FontSize;
            _language = settings.Language;
            _compactMode = settings.CompactMode;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        _errorMessage = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _successMessage = "Appearance settings saved!";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }
}

