@namespace sv_15f8c3b5f5974dadba9cf7b1dd6a1fa2.Components.Pages.Settings
@using sv_15f8c3b5f5974dadba9cf7b1dd6a1fa2.Models
@inject ISettingsService SettingsService

<div class="appearance-section">
    <h4 class="mb-4">Appearance Settings</h4>

    @if (_loading)
    {
        <div class="text-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                @* Theme *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Theme</h6>
                        @foreach (var theme in _themes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme}")" value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                @* Font Size *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Font Size</h6>
                        @foreach (var size in _fontSizes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size}")" value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>
                </div>

                @* Language *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Language</h6>
                        <select class="form-select" @bind="_language">
                            @foreach (var lang in _languages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>
                </div>

                @* Compact Mode *@
                <div class="card mb-4">
                    <div class="card-body">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch" id="compactMode"
                                   checked="@_compactMode" @onchange="e => _compactMode = (bool)e.Value!" />
                            <label class="form-check-label" for="compactMode">Compact Mode</label>
                        </div>
                        <small class="text-muted">Reduce spacing and padding throughout the interface.</small>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @if (_saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Save
                </button>

                @if (_successMessage is not null)
                {
                    <div class="alert alert-success alert-dismissible mt-3 fade show" role="alert">
                        @_successMessage
                        <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
                    </div>
                }
                @if (_errorMessage is not null)
                {
                    <div class="alert alert-danger alert-dismissible mt-3 fade show" role="alert">
                        @_errorMessage
                        <button type="button" class="btn-close" @onclick="() => _errorMessage = null"></button>
                    </div>
                }
            </div>

            @* Live Preview *@
            <div class="col-md-5">
                <div class="card sticky-top" style="top: 1rem;">
                    <div class="card-header">
                        <h6 class="mb-0">Live Preview</h6>
                    </div>
                    <div class="card-body preview-area @PreviewThemeClass" style="@PreviewFontStyle">
                        <div class="@(_compactMode ? "compact-preview" : "normal-preview")">
                            <h6>Sample Heading</h6>
                            <p>This is how your content will look with the selected settings.</p>
                            <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
                                <span class="badge bg-primary">Badge</span>
                                <span class="badge bg-secondary">Label</span>
